// ─── Public component ─────────────────────────────────────────────────────────
export default function ScreenBackground({ variant = 'home' }) {
  if (variant === 'login')         return <LoginBg />;
  if (variant === 'questionnaire') return <QuestionnaireBg />;
  return <HomeBg />;
}
